#!/usr/bin/env python3

from __future__ import annotations

import argparse
import json
import sys
from pathlib import Path
from typing import Any

SHARED = Path(__file__).resolve().parents[2] / "backlog-core" / "scripts"
sys.path.insert(0, str(SHARED))

from backlog_lib import (  # noqa: E402
    normalize_task_id,
    now_iso,
    rebuild_active_index,
    relative_link,
    slugify,
    state_dir,
    task_filename,
    write_markdown,
)
from generate_task_id import build_pool, collect_used_ids  # noqa: E402

MISSING = "information is missing"

SECTION_NAMES = [
    "Elevator's Pitch",
    "Business Gain",
    "Current State",
    "Desired State",
    "Definition of Success",
    "Additional Context",
    "Assumptions",
    "Constraints",
    "Acceptance Criteria",
    "Dos",
    "Don'ts",
    "Open Questions",
    "Related to",
]

SECTION_ALIASES = {
    "title": "title",
    "group": "group",
    "pitch": "Elevator's Pitch",
    "elevatorpitch": "Elevator's Pitch",
    "elevatorspitch": "Elevator's Pitch",
